// ─── STEP 1: Parse the outline JSON from OpenAI ───────────────────────────
const raw = $input.first().json;

// Grab shared context from Set Inputs
const setNode = $('Set Inputs').first().json;
const topic        = setNode.topic;
const output_type  = setNode.output_type;
const word_count   = setNode.word_count;
const email        = setNode.email;
const slack_enabled = setNode.slack_enabled;
const sheet_id     = setNode.sheet_id;
const serpapi_key  = setNode.serpapi_key;
const openai_key   = setNode.openai_key;
const timestamp    = setNode.timestamp;

// Parse OpenAI response
let outline;
try {
  const content = raw.choices[0].message.content;
  outline = JSON.parse(content);
} catch (e) {
  // Fallback outline if parsing fails
  outline = {
    working_title: topic,
    angles: [
      { angle: 'Overview',         search_query: `${topic} explained 2024`,                   why_important: 'Sets foundational context for the reader.' },
      { angle: 'Use Cases',        search_query: `${topic} real-world use cases examples`,    why_important: 'Shows practical applications readers can relate to.' },
      { angle: 'Data & Stats',     search_query: `${topic} statistics research data 2024`,    why_important: 'Adds credibility and quantifies the topic.' },
      { angle: 'Challenges',       search_query: `${topic} challenges problems limitations`,  why_important: 'Provides balanced perspective — builds trust.' },
      { angle: 'Future Trends',    search_query: `${topic} future trends predictions 2025`,   why_important: 'Gives readers forward-looking value.' }
    ]
  };
}

// Ensure we have exactly 5 angles
const angles = (outline.angles || []).slice(0, 5);
if (angles.length < 5) {
  console.log(`Warning: Only ${angles.length} angles found — padding with defaults`);
}

// Return one item per angle so SplitInBatches can loop through them
return angles.map((angle, index) => ({
  json: {
    angle_index: index,
    angle:         angle.angle         || `Angle ${index + 1}`,
    search_query:  angle.search_query  || `${topic} ${angle.angle}`,
    why_important: angle.why_important || '',
    working_title: outline.working_title || topic,
    // Carry context fields through the loop
    topic, output_type, word_count, email,
    slack_enabled, sheet_id, serpapi_key, openai_key, timestamp
  }
}));

// ─── STEP 2: Extract top results + carry context ─────────────────────────
const serpData = $input.first().json;
const loopItem = $('Loop Over Angles').item.json;  // context from current batch

// Extract top 3 organic results
const organicResults = serpData.organic_results || [];
const topResults = organicResults.slice(0, 3).map(r => ({
  title:   r.title   || '',
  snippet: r.snippet || '',
  link:    r.link    || ''
}));

// Also grab PAA (People Also Ask) if available — bonus context
const paaItems = (serpData.related_questions || []).slice(0, 2).map(q => q.question || '');

return [{
  json: {
    // Research data for this angle
    angle_index:   loopItem.angle_index,
    angle:         loopItem.angle,
    search_query:  loopItem.search_query,
    why_important: loopItem.why_important,
    results:       topResults,
    paa_questions: paaItems,
    results_count: topResults.length,
    // Carry all context fields
    working_title: loopItem.working_title,
    topic:         loopItem.topic,
    output_type:   loopItem.output_type,
    word_count:    loopItem.word_count,
    email:         loopItem.email,
    slack_enabled: loopItem.slack_enabled,
    sheet_id:      loopItem.sheet_id,
    serpapi_key:   loopItem.serpapi_key,
    openai_key:    loopItem.openai_key,
    timestamp:     loopItem.timestamp
  }
}];

// ─── STEP 3: Build structured research context for the draft writer ───────
const items = $input.all();

// The Aggregate node wraps everything in a 'data' array
const allAngles = items[0].json.data || items.map(i => i.json);

// Pull shared metadata from the first angle
const first        = Array.isArray(allAngles) ? allAngles[0] : allAngles;
const topic        = first.topic        || '';
const working_title = first.working_title || topic;
const word_count   = first.word_count   || 800;
const output_type  = first.output_type  || 'article';
const openai_key   = first.openai_key   || '';
const sheet_id     = first.sheet_id     || '';
const email        = first.email        || '';
const slack_enabled = first.slack_enabled !== undefined ? first.slack_enabled : false;
const timestamp    = first.timestamp    || new Date().toISOString();

// Build the research context string
const angleList = Array.isArray(allAngles) ? allAngles : [allAngles];
const contextParts = [];

for (const angle of angleList) {
  let section = `### Research Angle ${(angle.angle_index || 0) + 1}: ${angle.angle}\n`;
  section    += `Why this matters: ${angle.why_important}\n`;
  section    += `Search query used: "${angle.search_query}"\n`;

  const results = angle.results || [];
  if (results.length > 0) {
    section += `\nTop Sources Found:\n`;
    for (const r of results) {
      section += `• [${r.title}] — ${r.snippet}\n  URL: ${r.link}\n`;
    }
  }

  const paa = angle.paa_questions || [];
  if (paa.length > 0) {
    section += `\nPeople Also Ask:\n`;
    for (const q of paa) { section += `• ${q}\n`; }
  }

  contextParts.push(section);
}

const research_context = contextParts.join('\n---\n\n');

// Collect all source URLs for attribution
const allSources = [];
for (const angle of angleList) {
  for (const r of (angle.results || [])) {
    if (r.link && !allSources.includes(r.link)) allSources.push(r.link);
  }
}

return [{
  json: {
    topic,
    working_title,
    word_count,
    output_type,
    research_context,
    all_sources: allSources,
    angles_researched: angleList.length,
    openai_key,
    sheet_id,
    email,
    slack_enabled,
    timestamp
  }
}];

