// ─── STEP 4: Parse the final draft from OpenAI ────────────────────────────
const raw  = $input.first().json;
const prev = $('Build Research Context').first().json;

let draft;
try {
  const content = raw.choices[0].message.content;
  draft = JSON.parse(content);
} catch (e) {
  // Graceful fallback
  draft = {
    title:               prev.working_title,
    meta_description:    `A comprehensive ${prev.output_type} about ${prev.topic}. Research-backed insights from ${prev.angles_researched} angles.`,
    draft:               `# ${prev.working_title}\n\n*Research-based ${prev.output_type} on: ${prev.topic}*\n\n${prev.research_context}`,
    key_points:          [`Overview of ${prev.topic}`, 'Practical applications', 'Future trends'],
    key_sources:         prev.all_sources.slice(0, 3),
    word_count_estimate: prev.word_count,
    reading_time_minutes: Math.ceil(prev.word_count / 200)
  };
}

return [{
  json: {
    // Final content
    title:                draft.title               || prev.working_title,
    meta_description:     draft.meta_description    || '',
    draft:                draft.draft               || '',
    key_points:           draft.key_points          || [],
    key_sources:          draft.key_sources         || prev.all_sources.slice(0, 3),
    word_count_estimate:  draft.word_count_estimate || prev.word_count,
    reading_time_minutes: draft.reading_time_minutes || Math.ceil(prev.word_count / 200),
    // Metadata
    topic:             prev.topic,
    output_type:       prev.output_type,
    angles_researched: prev.angles_researched,
    all_sources:       prev.all_sources,
    // Config
    openai_key:   prev.openai_key,
    sheet_id:     prev.sheet_id,
    email:        prev.email,
    slack_enabled: prev.slack_enabled,
    timestamp:    prev.timestamp
  }
}];

